mapper.select:
select r.*, c.course_name, u.real_name as teacher_name from weekly_recipe r left join activity_info c on r.course_id = c.id left join sys_user u on r.teacher_id = u.id
and r.schedule_id = #{scheduleId}
and r.teacher_id = #{teacherId}
and r.title like concat('%', #{keyword}, '%')
order by r.id desc

mapper.update:
update weekly_recipe
schedule_id = #{scheduleId}, course_id = #{courseId}, title = #{title}, resource_type = #{resourceType}, resource_url = #{resourceUrl}, content_desc = #{contentDesc}, status = #{status},
where id = #{id}
